def sort_list(data: list[int]) -> list[int]:
    if len(data) < 500:
        return sorted(data)

    # Check if we can use counting sort for small range
    min_val = min(data)
    max_val = max(data)
    range_size = max_val - min_val + 1

    if range_size <= len(data) * 2:  # Use counting sort for dense ranges
        counts = [0] * range_size
        for val in data:
            counts[val - min_val] += 1

        result = []
        for i, count in enumerate(counts):
            if count > 0:
                result.extend([i + min_val] * count)
        return result

